/** UsptStdrApplyRealmDao.insert */
insert into uspt_stdr_apply_realm
						(
							apply_realm_id
							, stdr_bsns_cd
							, apply_realm_nm
							, creator_id
							, created_dt
							, updater_id
							, updated_dt
						)
				values	(
							#{applyRealmId}
							, #{stdrBsnsCd}
							, #{applyRealmNm}
							, #{creatorId}
							, #{createdDt}
							, #{updaterId}
							, #{updatedDt}
						)

mapper.update:
/** UsptStdrApplyRealmDao.update */
update uspt_stdr_apply_realm
set
	apply_realm_nm = #{applyRealmNm}
	, updater_id = #{updaterId}
	, updated_dt = #{updatedDt}
where
	apply_realm_id = #{applyRealmId}
	and stdr_bsns_cd = #{stdrBsnsCd}

